import{_ as s,o as t,c as a,ag as i}from"./chunks/framework.B3ZMliSr.js";const k=JSON.parse('{"title":"Webhooks","description":"setWebhook, deleteWebhook, getWebhookInfo, delivery semantics, and SSRF protection.","frontmatter":{"title":"Webhooks","description":"setWebhook, deleteWebhook, getWebhookInfo, delivery semantics, and SSRF protection."},"headers":[],"relativePath":"bot-api/webhooks.md","filePath":"bot-api/webhooks.md","lastUpdated":1783313024000}'),o={name:"bot-api/webhooks.md"};function n(r,e,l,d,h,p){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h1><p>Instead of long-polling, point the server at an HTTPS endpoint and it will deliver updates as they arrive. Delivery mirrors the official <code>WebhookActor</code> semantics.</p><h2 id="basic-usage" tabindex="-1">Basic usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic usage&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Set a webhook</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8081/bot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">TOKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">N</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/setWebhook</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;url=https://example.com/webhook&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;secret_token=mysecret&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check webhook status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8081/bot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">TOKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">N</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/getWebhookInfo</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Delete (switch back to polling)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8081/bot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">TOKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">N</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/deleteWebhook</span></span></code></pre></div><p><code>setWebhook</code> returns only after the server has confirmed outbound <strong>TCP/TLS readiness</strong> to the webhook URL — so a successful response means your endpoint is actually reachable, not just accepted.</p><h2 id="delivery-semantics" tabindex="-1">Delivery semantics <a class="header-anchor" href="#delivery-semantics" aria-label="Permalink to &quot;Delivery semantics&quot;">​</a></h2><ul><li><strong>Verification</strong> — <code>setWebhook</code> returns only after confirming outbound TCP/TLS readiness to the webhook URL.</li><li><strong>Concurrency</strong> — respects <code>max_connections</code> per bot (configurable via <code>--max-webhook-connections</code>, default <code>100</code>).</li><li><strong>Ordering</strong> — events within a single queue are delivered in order.</li><li><strong>Retry</strong> — exponential backoff with a <code>Retry-After</code> header clamp and a randomized resend cap.</li><li><strong>Expiry</strong> — events past their TTL are dropped (not retried forever).</li><li><strong>Sustained 410</strong> — repeated <code>410 Gone</code> responses close the webhook.</li><li><strong>DNS/IP cache</strong> — resolved endpoints are cached to avoid redundant lookups.</li><li><strong>Flood gates</strong> — active and pending connection counts are flood-controlled.</li></ul><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>url</code></td><td>HTTPS endpoint to deliver to. Send empty (with <code>drop_pending_updates</code>) to delete.</td></tr><tr><td><code>secret_token</code></td><td>Optional token sent in the <code>X-Telegram-Bot-Api-Secret-Token</code> header on every delivery.</td></tr><tr><td><code>max_connections</code></td><td>Max simultaneous in-flight deliveries (≤ <code>--max-webhook-connections</code>).</td></tr><tr><td><code>allowed_updates</code></td><td>Per-webhook update-type whitelist (see <a href="/website/bot-api/updates#allowed-updates-filtering">Updates</a>).</td></tr><tr><td><code>ip_address</code></td><td>Fixed IP to connect to (bypasses DNS).</td></tr><tr><td><code>drop_pending_updates</code></td><td>Drop all pending updates before switching.</td></tr></tbody></table><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">SSRF protection</p><p>Outgoing webhook requests are validated against an IP blocklist — loopback, link-local, and private ranges — to prevent server-side request forgery. A webhook URL that resolves into a blocked range is rejected.</p><p>All outgoing webhook requests also carry connect, read, and write timeouts, and an <code>--proxy</code> may be configured for egress.</p></div><p>Bot tokens are validated for format (shape + checksum) before client creation, returning official <code>401</code> / <code>421</code> envelopes for malformed tokens. Token values are never logged.</p><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>A webhook receiver for testing is included at <a href="https://github.com/mtgo-labs/mtgo-bot-api/tree/main/examples/webhook" target="_blank" rel="noreferrer"><code>examples/webhook/receiver.ts</code></a> in the mtgo-bot-api repo. Run it locally and point <code>setWebhook</code> at it to observe delivery, retries, and headers:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">token</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/webhook/receiver.ts</span></span></code></pre></div>`,15)])])}const g=s(o,[["render",n]]);export{k as __pageData,g as default};
